class Solution:
    def kIncreasing(self, arr, k):
        n = len(arr)
        total = 0
        for r in range(k):
            seq = arr[r::k]
            m = len(seq)
            dp = [1] * m
            for i in range(m):
                for j in range(i):
                    if seq[j] <= seq[i] and dp[j] + 1 > dp[i]:
                        dp[i] = dp[j] + 1
            best = max(dp) if dp else 0
            total += m - best
        return total

