import bisect

class Solution:
    def kIncreasing(self, arr, k):
        n = len(arr)
        total_ops = 0
        for r in range(k):
            seq = arr[r::k]
            tails = []
            for x in seq:
                idx = bisect.bisect_right(tails, x)
                if idx == len(tails):
                    tails.append(x)
                else:
                    tails[idx] = x
            total_ops += len(seq) - len(tails)
        return total_ops

