var kIncreasing = function(arr, k) {
    const n = arr.length;
    let total = 0;
    for (let r = 0; r < k; r++) {
        const seq = [];
        for (let i = r; i < n; i += k) seq.push(arr[i]);
        const tails = [];
        for (const x of seq) {
            let lo = 0, hi = tails.length;
            while (lo < hi) {
                const mid = (lo + hi) >> 1;
                if (tails[mid] > x) hi = mid; else lo = mid + 1;
            }
            if (lo === tails.length) tails.push(x); else tails[lo] = x;
        }
        total += seq.length - tails.length;
    }
    return total;
};
